const sc = $('ScrapeCreators').first().json || {};
const list = (sc.search_item_list||[]).map(it=>{const a=it.aweme_info||{};return {d:(a.desc||'').trim(),v:(a.statistics||{}).play_count||0};}).filter(x=>x.d).sort((a,b)=>b.v-a.v).slice(0,8);
const signals = list.map((r,i)=>`${i+1}. [${r.v.toLocaleString('ru-RU')}] ${r.d}`).join('\n') || '(нет данных)';
let trends='(нет)';
try{ trends = $('Perplexity').first().json.choices[0].message.content; }catch(e){}
return [{ json: { signals_text: signals, trends_text: trends } }];

const raw=$input.first().json.candidates[0].content.parts[0].text;
const idea=JSON.parse(raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim());
const t=+idea.trend_score||0,u=+idea.usefulness_score||0,v=+idea.viral_score||0,pf=+idea.product_fit_score||0;
idea.total=+(t*0.2+u*0.3+v*0.25+pf*0.25).toFixed(2);
const s=(idea.topic||'').toLowerCase().replace(/[^0-9a-zа-яё ]/gi,'').replace(/\s+/g,' ').trim();
let h=5381; for(let i=0;i<s.length;i++){h=(((h<<5)+h)+s.charCodeAt(i))&0xffffffff;}
idea.topic_hash='h'+(h>>>0).toString(16);
idea.start_code='YT'+(h>>>0).toString(16).toUpperCase().slice(0,6);
return [{ json: idea }];

const idea=$('Parse idea').first().json;
const raw=$input.first().json.candidates[0].content.parts[0].text;
const concept=JSON.parse(raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim());
const rt=v=>({rich_text:[{text:{content:String(v==null?'':v).slice(0,1900)}}]});
const cjson=JSON.stringify(concept);
const chunks=[]; for(let i=0;i<cjson.length;i+=1900){ chunks.push({text:{content:cjson.slice(i,i+1900)}}); }
const link='https://t.me/foodgenius_ai_bot?start=ref_'+idea.start_code;
const caption=(concept.caption||idea.topic)+'\n\n'+(concept.cta||'')+' '+link;
const props={
  'title':{title:[{text:{content:String(idea.topic||'без темы').slice(0,1900)}}]},
  'status':{select:{name:'Needs Review'}},
  'platform':{select:{name:'youtube'}},
  'content_format':rt('video/shorts'),
  'post_text':rt(concept.hook_text||''),
  'final_text':{rich_text: chunks},
  'cta':rt(concept.cta||''),
  'start_code':rt(idea.start_code),
  'target_audience':{select:{name:String(idea.audience_segment||'занятые').split('|')[0].trim()}},
  'post_hash':rt(idea.topic_hash),
  'created_at':{date:{start:new Date().toISOString()}},
  'updated_at':{date:{start:new Date().toISOString()}}
};
return [{ json: { topic: idea.topic, total: idea.total, start_code: idea.start_code, caption, notion_props: props } }];

const res=($input.first().json.results)||[];
if(!res.length){return [];}
const p=res[0]; const pr=p.properties;
const g=(n,t)=>{const x=pr[n]||{}; if(t=='title')return (x.title||[]).map(z=>z.plain_text).join(''); if(t=='rt')return (x.rich_text||[]).map(z=>z.plain_text).join(''); return '';};
if(g('external_post_id','rt')){ return []; }
let c={}; try{ c=JSON.parse(g('final_text','rt')); }catch(e){}
const scenes=(c.scenes||[]).map(s=>({footage_query:s.footage_query||'healthy food cooking', onscreen_text:s.onscreen_text||'', dur:s.dur||3.5}));
return [{json:{page_id:p.id, title:g('title','title').slice(0,95), start_code:g('start_code','rt'), music_mood:(c.music_mood||'upbeat positive'), caption:(c.caption||g('title','title')), cta:(c.cta||''), scenes}}];

const ress=$input.all(); const splits=$('Split scenes').all(); const scenes=[];
for(let i=0;i<ress.length;i++){ const d=ress[i].json||{}; const vids=d.videos||[]; let url=null;
 for(const v of vids){ let files=(v.video_files||[]).filter(f=>f.height>f.width); files=files.filter(f=>f.height>=1000&&f.height<=1920); files.sort((a,b)=>a.height-b.height); if(files.length){url=files[files.length-1].link;break;} }
 const sc=(splits[i]||{}).json||{}; if(url) scenes.push({url, onscreen_text:sc.onscreen_text||'', dur:sc.dur||3.5}); }
return [{json:{scenes}}];

const pc=$('Parse concept').first().json; const scenes=$('Pick clip').first().json.scenes||[];
let music_url=null, music_attr='';
try{ const tr=($input.first().json.results||[]).find(t=>t.audio); if(tr){ music_url=tr.audio; music_attr='Музыка: '+tr.name+' — '+tr.artist_name+' (Jamendo)'; } }catch(e){}
const job={scenes, packshot:{text:'FoodGenius', cta:(pc.cta||'Бесплатный помощник — ссылка в описании'), dur:2.5}};
if(music_url) job.music_url=music_url;
const job_b64=Buffer.from(JSON.stringify(job)).toString('base64');
const link='https://t.me/foodgenius_ai_bot?start=ref_'+pc.start_code;
const description=(pc.caption||pc.title)+'\n\n'+(pc.cta||'')+'\n'+link+'\n\n'+music_attr+'\n#shorts';
return [{json:{job_b64, title:pc.title, description, page_id:pc.page_id}}];

const b64=(($input.first().json.stdout)||'').trim(); if(!b64) throw new Error('empty render output');
const buf=Buffer.from(b64,'base64');
const bin=await this.helpers.prepareBinaryData(buf,'foodgenius_shorts.mp4','video/mp4');
return [{json:{size:buf.length}, binary:{data:bin}}];
